import React, { useState } from 'react';
import Navbar from './Navbar';
import EnquiryModal from './EnquiryModal';

function About() {
  const [showModal, setShowModal] = useState(false);

  return (
    <>
      <Navbar onEnquire={() => setShowModal(true)} />

      <section className="second-hero">
        <div className="overlay" />

        <div className="about-content">
          <h1>We are not a typical training institute.</h1>

          <p className="line1">
            We are a team of engineers who asked one simple question:
          </p>

          <p className="highlight">
            "Why are students still not ready for real-world jobs?"
          </p>

          <p className="line2">And we found the answer.</p>
        </div>

        <div className="about-extra">
          <p className="problems">
            Too much theory &nbsp; | &nbsp; Less practical exposure &nbsp; | &nbsp; No real skill development
          </p>

          <h2>So we built Yathirai Infotech.</h2>

          <p className="final-line">
            We don't just teach. We help you become job-ready.
          </p>
        </div>
      </section>

      {showModal && <EnquiryModal onClose={() => setShowModal(false)} />}
    </>
  );
}

export default About;
